window.PACTO.acts["reg-2019-816"]={"label": "REGOLAMENTO (UE) 2019/816 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2019/816", "file": "ext-reg-2019-816.html", "external": true, "version": "consolidato 2026-06-12", "eurlex": "https://eur-lex.europa.eu/eli/reg/2019/816/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento stabilisce:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema per individuare gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di cittadini di paesi terzi («ECRIS-TCN»);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni alle quali ECRIS-TCN è usato dalle autorità centrali al fine di ottenere informazioni su tali condanne precedenti attraverso il sistema europeo di informazione sui casellari giudiziali (ECRIS) istituito con decisione 2009/316/GAI, nonché le condizioni alle quali l'Eurojust, l'Europol e l'EPPO usano ECRIS-TCN;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni alle quali l'ECRIS-TCN concorre ad agevolare e contribuire alla corretta identificazione delle persone registrate nell'ECRIS-TCN conformemente alle condizioni e ai fini di cui all'articolo 20 del regolamento (UE) 2019/818 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n), conservando nel CIR i dati di identità, i dati del documento di viaggio e i dati biometrici;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni alle quali i dati nell’ECRIS-TCN possono essere utilizzati dalle autorità designate per il VIS di cui all’articolo 9 <span class=\"italics\">quinquies</span> e all’articolo 22 <span class=\"italics\">ter</span>, paragrafo 13 del regolamento (CE) n. 767/2008 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n) al fine di valutare se un richiedente un visto, un visto per soggiorno di lunga durata o un permesso di soggiorno possa costituire una minaccia per l’ordine pubblico o la sicurezza interna di cui all’articolo 2, paragrafo 1, lettera i), e dell’articolo 2, paragrafo 2, lettera a), di tale regolamento;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni alle quali i dati di ECRIS-TCN possono essere utilizzati dall’Unità centrale ETIAS, istituita nell’ambito dell’Agenzia europea della guardia di frontiera e costiera a norma dell’articolo 7 del regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n), al fine di sostenere l’obiettivo dell’ETIAS di contribuire a un elevato livello di sicurezza permettendo una valutazione approfondita del rischio per la sicurezza presentato dai richiedenti prima del loro arrivo ai valichi di frontiera esterni, onde determinare se vi siano indicazioni concrete o fondati motivi basati su indicazioni concrete per concludere che la presenza di una persona nel territorio degli Stati membri presenta un rischio per la sicurezza;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni alle quali i dati di ECRIS-TCN possono essere usati dalle autorità preposte agli accertamenti quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n) per effettuare un controllo di sicurezza al fine di valutare se un cittadino di paese terzo possa costituire una minaccia per la sicurezza interna di cui all’articolo 15 di tale regolamento.</p>\n</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Il presente regolamento si applica al trattamento delle informazioni sull’identità dei cittadini di paesi terzi che sono stati oggetto di condanne negli Stati membri, allo scopo di individuare gli Stati membri in cui sono state pronunciate tali condanne. Ad eccezione dell’articolo 5, paragrafo 1, lettera b), punto ii), le disposizioni del presente regolamento che si applicano ai cittadini di paesi terzi si applicano anche ai cittadini dell’Unione che hanno anche la cittadinanza di un paese terzo e che sono stati oggetto di condanne negli Stati membri.</p>"], [null, "<p class=\"norm\">Il presente regolamento:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene l’obiettivo del VIS di valutare se il richiedente un visto, un visto per soggiorno di lunga durata o un permesso di soggiorno costituisca una minaccia per l’ordine pubblico o la sicurezza pubblica, in conformità del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene l’obiettivo dell’ETIAS di contribuire a un elevato livello di sicurezza, in conformità del regolamento (UE) 2018/1240;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agevola e coadiuva nella corretta identificazione delle persone, in conformità del presente regolamento e del regolamento (UE) 2019/818;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consente l’accesso a ECRIS-TCN ai fini dello svolgimento del controllo di sicurezza stabilito dal regolamento (UE) 2024/1356.</p>\n</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le seguenti definizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«condanna», la decisione definitiva di una giurisdizione penale nei confronti di una persona fisica in relazione a un reato, nella misura in cui tale decisione sia riportata nel casellario giudiziale dello Stato membro di condanna;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«procedimento penale», la fase precedente al processo penale, la fase del processo penale stesso e l'esecuzione della condanna;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«casellario giudiziale», il registro nazionale o i registri nazionali in cui le condanne sono registrate conformemente al diritto nazionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«Stato membro di condanna», lo Stato membro in cui è stata pronunciata una condanna;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«autorità centrale«, un'autorità designata conformemente all'articolo 3, paragrafo 1, della decisione quadro 2009/315/GAI;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«autorità competenti«, le autorità centrali, Eurojust, Europol, EPPO, le autorità designate del VIS di cui all’articolo 9 quinquies e all’articolo 22 ter, paragrafo 13, del regolamento (CE) n. 767/2008, <span class=\"stroke\">e</span> l’unità centrale ETIAS e le autorità preposte agli accertamenti definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356 che sono competenti ad accedere a ECRIS-TCN o ad interrogarlo a norma del presente regolamento;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadino di paese terzo», chiunque non sia cittadino dell'Unione ai sensi dell'articolo 20, paragrafo 1, TFUE, l'apolide o qualsiasi persona la cui cittadinanza è ignota;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«software di interfaccia», il software ospitato dalle autorità competenti che consente loro di accedere al sistema centrale tramite l'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«informazioni sull'identità», i dati alfanumerici, i dati relativi alle impronte digitali e le immagini del volto utilizzati per stabilire una connessione tra tali dati e una persona fisica;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dati alfanumerici», i dati rappresentati da lettere, cifre, caratteri speciali, spazi e segni di punteggiatura;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dati relativi alle impronte digitali», i dati relativi alle impressioni piatte e rollate delle impronte digitali di ciascun dito di una persona;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«immagine del volto», le immagini digitalizzate del volto di una persona;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>14) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«riscontro positivo», la o le corrispondenze constatate, sulla base di un confronto, tra le informazioni sull'identità registrate nel sistema centrale e le informazioni sull'identità usate per interrogare il sistema;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>15) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«punto di accesso centrale nazionale», il punto nazionale di connessione all'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>16) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«implementazione di riferimento ECRIS», il software sviluppato dalla Commissione e messo a disposizione degli Stati membri per lo scambio delle informazioni sui casellari giudiziali tramite ECRIS;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>17) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«autorità nazionale di controllo», un'autorità pubblica indipendente istituita da uno Stato membro in conformità delle norme dell'Unione in materia di protezione dei dati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>18) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«autorità di controllo», il Garante europeo della protezione dei dati e le autorità nazionali di controllo;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>19) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«CIR», l'archivio comune di dati di identità quale istituito dall'articolo 17, paragrafo 1, del regolamento (UE) 2019/818;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>20) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dati dell'ECRIS-TCN», tutti i dati conservati nel sistema centrale dell'ECRIS-TCN e nel CIR conformemente all'articolo 5;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>21) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«ESP», il portale di ricerca europeo istituito dall'articolo 6, paragrafo 1, del regolamento (UE) 2019/818.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "4": {"label": "Articolo 4", "heading": "Architettura tecnica di ECRIS-TCN", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">ECRIS-TCN consta di:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema centrale;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il CIR;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un punto di accesso centrale nazionale in ciascuno Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un software di interfaccia che connette le autorità competenti al sistema centrale tramite il punto di accesso centrale nazionale e l'infrastruttura di comunicazione di cui alla lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'infrastruttura di comunicazione tra il sistema centrale e il punto di accesso centrale nazionale;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'infrastruttura di comunicazione tra il sistema centrale e le infrastrutture centrali dell'ESP e del CIR.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sistema centrale è ospitato da eu-LISA presso i suoi siti tecnici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il software di interfaccia è integrato con l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>. Gli Stati membri usano l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> o, nella situazione e alle condizioni di cui ai paragrafi da 4 a 8, il software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span>, per interrogare ECRIS-TCN e per trasmettere le successive richieste di informazioni sui casellari giudiziali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che utilizzano il proprio software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> sono tenuti a garantire che esso consenta alle loro autorità nazionali incaricate dei casellari giudiziali di utilizzare ECRIS-TCN, a eccezione del software di interfaccia, conformemente al presente regolamento. A tale scopo, prima della data di entrata in funzione di ECRIS-TCN ai sensi dell'articolo 35, paragrafo 4, essi garantiscono che il loro software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> funzioni conformemente ai protocolli e alle specifiche tecniche definite negli atti di esecuzione di cui all'articolo 10 e a eventuali altri requisiti tecnici definiti da eu-LISA ai sensi del presente regolamento basati su detti atti di esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fintanto che non usano l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, gli Stati membri che usano il proprio software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> garantiscono inoltre l'introduzione nel loro software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> dei successivi adattamenti tecnici resi necessari da eventuali modifiche delle specifiche tecniche definite negli atti di esecuzione di cui all'articolo 10 o da modifiche di eventuali altri requisiti tecnici definiti da eu-LISA ai sensi del presente regolamento basati su detti atti di esecuzione, senza ingiustificato ritardo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che usano il proprio software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> sostengono tutte le spese associate all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione<span class=\"boldface\"> ◄ </span>, alla manutenzione e all'ulteriore sviluppo del loro software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span> e alla sua interconnessione con ECRIS-TCN, con l'eccezione del software di interfaccia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro che usa il proprio software di implementazione ECRIS non sia in grado di conformarsi agli obblighi di cui al presente articolo, ha l'obbligo di usare l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, incluso il software di interfaccia integrato, per avvalersi di ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Alla luce della valutazione che la Commissione è tenuta a effettuare ai sensi dell'articolo 36, paragrafo 10, lettera b), gli Stati membri interessati forniscono alla Commissione tutte le informazioni necessarie.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Inserimento dei dati in ECRIS-TCN", "anchor": "art_5", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per ciascun cittadino condannato di un paese terzo, l'autorità centrale dello Stato membro di condanna crea un registro dei dati in ECRIS-TCN. La registrazione dei dati comprende:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda i dati alfanumerici:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni da includere a meno che, in singoli casi, tali informazioni non siano note all'autorità centrale (informazioni obbligatorie):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">cognome;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">nome o nomi;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">data di nascita;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">luogo di nascita (città e paese);</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">la o le cittadinanze;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sesso;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">nomi precedenti, se del caso;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">codice dello Stato membro di condanna;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni da includere se sono state inserite nel casellario giudiziale (informazioni facoltative):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">nome dei genitori;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni da includere se sono a disposizione dell'autorità centrale (informazioni supplementari):</p>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">numero di identità, o tipo e numero dei documenti di identificazione dell’interessato, compresi i titoli di viaggio, nonché denominazione dell’autorità di rilascio;</div>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">eventuali pseudonimi o alias;</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda i dati relativi alle impronte digitali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati relativi alle impronte digitali che sono stati rilevati conformemente al diritto nazionale nel corso di procedimenti penali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">come minimo, dati relativi alle impronte digitali rilevati in base a uno dei seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se il cittadino di paese terzo è stato condannato a una pena detentiva di almeno sei mesi;</div>\n<div class=\"list\">o</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se il cittadino di paese terzo è stato condannato per un reato punibile, a norma del diritto dello Stato membro, con una pena detentiva della durata massima non inferiore a 12 mesi;</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un indicatore che segnali, ai fini dei regolamenti (CE) n. 767/2008 e (UE) 2018/1240 e degli articoli 15 e 16 del regolamento (UE) 2024/1356, che il cittadino di paese terzo interessato è stato condannato nei 25 anni precedenti per un reato di terrorismo o nei 15 anni precedenti per qualunque altro dei reati elencati nell’allegato del regolamento (UE) 2018/1240, qualora tale reato sia punibile con una pena detentiva o una misura di sicurezza privativa della libertà personale per un periodo massimo di almeno tre anni conformemente al diritto nazionale, tra cui il codice dello Stato membro di condanna.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Il CIR contiene i dati di cui al paragrafo 1, lettera b), e i seguenti dati di cui al paragrafo 1, lettera a): cognome, nome o nomi, data di nascita, luogo di nascita (città e paese), la o le cittadinanze, sesso, se del caso, nomi precedenti e, ove disponibili, pseudonimi o alias, come pure, ove disponibili, tipo e numero del documento o dei documenti di viaggio dell’interessato, nonché denominazione dell’autorità di rilascio.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il CIR può inoltre contenere i dati di cui al paragrafo 3, nonché, nei casi di cui al paragrafo 1, lettera c), il codice dello Stato membro di condanna. I rimanenti dati di ECRIS-TCN sono conservati nel sistema centrale.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati relativi alle impronte digitali di cui al paragrafo 1, lettera b), del presente articolo devono soddisfare le specifiche tecniche per la qualità, la risoluzione e il trattamento dei dati relativi alle impronte digitali previste negli atti di esecuzione di cui all'articolo 10, paragrafo 1, lettera b). Il numero di riferimento dei dati relativi alle impronte digitali della persona condannata include il codice dello Stato membro di condanna.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La registrazione di dati può contenere anche le immagini del volto del cittadino di paese terzo condannato, qualora il diritto dello Stato membro di condanna consenta di raccogliere e conservare le immagini del volto delle persone condannate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro di condanna crea la registrazione di dati automaticamente, ove possibile, e senza ingiustificato ritardo dopo l'iscrizione della condanna nel casellario giudiziale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri di condanna creano inoltre la registrazione di dati per le condanne pronunciate prima della data di entrata in funzione dei dati ai sensi dell'articolo 35, paragrafo 1, nella misura in cui i dati relativi alle persone condannate sono conservati nelle loro banche dati nazionali. In tali casi i dati relativi alle impronte digitali devono essere inclusi soltanto se sono state rilevate nel corso di procedimenti penali conformemente al diritto nazionale e se è possibile stabilire una chiara corrispondenza con altre informazioni sull'identità contenute nei casellari giudiziali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al fine di rispettare gli obblighi di cui al paragrafo 1, lettera b), punti i) e ii), e al paragrafo 5, gli Stati membri possono utilizzare i dati relativi alle impronte digitali rilevate a fini diversi da un procedimento penale, qualora tale uso sia autorizzato dal diritto nazionale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">gli indicatori e i codici dello Stato membro di condanna di cui al paragrafo 1, lettera c), del presente articolo, sono accessibili e consultabili soltanto da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sistema centrale del VIS, istituito dall’articolo 2 <span class=\"italics\">bis</span>, paragrafo 1, lettera b) del regolamento (CE) n. 767/2008, ai fini delle verifiche a norma dell’articolo 7 <span class=\"italics\">bis</span> del presente regolamento, in combinato disposto con l’articolo 9 <span class=\"italics\">bis</span>, paragrafo 4, lettera e), o con l’articolo 22 <span class=\"italics\">ter</span>, paragrafo 3, lettera e), del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sistema centrale ETIAS, quale definito all’articolo 3, paragrafo 1, punto 25) del regolamento (UE) 2018/1240 ai fini delle verifiche a norma dell’articolo 7 <span class=\"italics\">ter</span> del presente regolamento, in combinato disposto con l’articolo 20, paragrafo 2, lettera n), del regolamento (UE) 2018/1240, qualora emergano riscontri positivi in seguito alla verifica automatizzata a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b), di detto regolamento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le autorità preposte agli accertamenti quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356, per valutare se il cittadino di un paese terzo possa rappresentare una minaccia per la sicurezza interna nel caso in cui emergano riscontri positivi a seguito del controllo di sicurezza di cui agli articoli 15 e 16 di tale regolamento.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo il primo comma del presente paragrafo, gli indicatori e il codice dello Stato membro di condanna di cui al paragrafo 1, lettera c), non sono visibili a nessun’altra autorità a eccezione dell’autorità centrale dello Stato membro di condanna che ha creato la registrazione dei dati provvista di indicatore.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Immagini del volto", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fino all'entrata in vigore dell'atto delegato di cui al paragrafo 2, le immagini del volto possono essere utilizzate al solo scopo di confermare l'identità del cittadino di paese terzo identificato grazie all'interrogazione con dati alfanumerici o con dati relativi alle impronte digitali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 37 al fine di integrare il presente regolamento per quanto riguarda l'uso delle immagini del volto ai fini dell'identificazione di cittadini di paesi terzi in modo da individuare, quando sarà possibile a livello tecnico, gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di tali persone. Prima di esercitare tale potere, la Commissione valuta, tenendo conto della necessità e della proporzionalità, nonché degli sviluppi tecnici nel settore del software di riconoscimento facciale, la disponibilità e lo stato di preparazione della tecnologia necessaria.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Utilizzo di ECRIS-TCN per individuare gli Stati membri in possesso di informazioni sui casellari giudiziali", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità centrali usano ECRIS-TCN per individuare gli Stati membri in possesso di informazioni sul casellario giudiziale di un cittadino di paese terzo, al fine di ottenere informazioni sulle precedenti condanne tramite ECRIS, quando dette informazioni su tale persona sono richieste nello Stato membro in questione ai fini di un procedimento penale nei confronti di quella persona o per uno qualsiasi dei seguenti fini, se previsto conformemente al diritto nazionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">permettere a una persona, su sua richiesta, di verificare il proprio casellario giudiziale;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">rilasciare nulla osta di sicurezza;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">ottenere una licenza o un permesso;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">effettuare indagini di sicurezza a fini occupazionali;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">effettuare indagini di sicurezza in vista di attività di volontariato che prevedono contatti diretti e regolari con minori o persone vulnerabili;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">espletare le procedure in materia di visti, acquisizione della cittadinanza e migrazione, comprese quelle di asilo; ed</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">effettuare controlli in relazione ad appalti pubblici e concorsi pubblici.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ciononostante, in casi specifici diversi da quelli in cui un cittadino di paese terzo chiede all'autorità centrale informazioni sul proprio casellario, o quando la richiesta è presentata per ottenere informazioni dal casellario giudiziale a norma dell'articolo 10, paragrafo 2, della direttiva 2011/93/UE, l'autorità che chiede informazioni sui casellari giudiziali può decidere che tale uso di ECRIS-TCN non è adeguato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro che decida, se previsto conformemente al diritto nazionale, di usare ECRIS-TCN per fini diversi da quelli indicati al paragrafo 1, allo scopo di ottenere informazioni su precedenti condanne tramite ECRIS, entro la data di entrata in funzione di cui all'articolo 35, paragrafo 4, o successivamente, notifica alla Commissione tali fini e le eventuali modifiche. La Commissione pubblica altresì tali notifiche nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> entro 30 giorni dal ricevimento della notifica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Eurojust, Europol ed EPPO sono legittimati a interrogare ECRIS-TCN per individuare gli Stati membri in possesso di informazioni sul casellario giudiziale di un cittadino di paese terzo in conformità degli articoli da 14 a 18. Ciononostante, non inseriscono, rettificano o cancellano dati in ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini di cui ai paragrafi 1, 2 e 3, le autorità competenti possono inoltre interrogare ECRIS-TCN per verificare se, con riguardo a un cittadino dell'Unione, uno o più Stati membri siano in possesso di informazioni sul casellario giudiziale di tale persona in quanto cittadino di paese terzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando interrogano ECRIS-TCN, le autorità competenti possono usare tutti o soltanto alcuni dei dati di cui all'articolo 5, paragrafo 1. L'insieme minimo di dati necessari per interrogare il sistema è specificato in un atto di esecuzione adottato in conformità dell'articolo 10, paragrafo 1, lettera g).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le autorità competenti possono interrogare ECRIS-TCN anche usando le immagini del volto, sempreché tale funzionalità sia stata attuata a norma dell'articolo 6, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di riscontro positivo il sistema centrale o il CIR trasmette automaticamente all’autorità competente informazioni sugli Stati membri in possesso di informazioni sui precedenti penali del cittadino di paese terzo, insieme con i numeri di riferimento associati di cui all’articolo 5, paragrafo 1, e alle corrispondenti informazioni sull’identità. Le informazioni sull’identità sono utilizzate solo per verificare l’identità del cittadino di paese terzo. Il risultato di un’interrogazione del sistema centrale è utilizzato al solo scopo di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">introdurre una richiesta ai sensi dell’articolo 6 della decisione quadro 2009/315/GAI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">introdurre una richiesta di cui all’articolo 17, paragrafo 3, del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo del VIS di valutare se il richiedente un visto, un visto per soggiorno di lunga durata o un permesso di soggiorno possa costituire una minaccia per l’ordine pubblico o la sicurezza interna, in conformità del regolamento (CE) n. 767/2008; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo dell’ETIAS di contribuire a un elevato livello di sicurezza, in conformità del regolamento (UE) 2018/1240; oppure</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo di valutare se un cittadino di paese terzo soggetto a un controllo di sicurezza possa rappresentare una minaccia per la sicurezza interna, conformemente al regolamento (UE) 2024/1356.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">In assenza di riscontro positivo, il sistema centrale ne informa automaticamente l'autorità competente.</div>\n</div>"]]}, "7a": {"label": "Articolo 7 bis", "heading": "Utilizzo dell’ECRIS-TCN per le verifiche VIS", "anchor": "art_7a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A decorrere dalla data di entrata in funzione del VIS a norma dell’articolo 11 del regolamento (UE) 2021/1134 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n), ECRIS-TCN è collegato all’ESP per consentire il trattamento automatizzato ai sensi degli articoli 9 <span class=\"italics\">bis</span> e 22 <span class=\"italics\">ter</span> del regolamento (CE) n. 767/2008 per interrogare ECRIS-TCN e confrontare i dati pertinenti nel VIS con i dati pertinenti di ECRIS-TCN conservati nel CIR, corredati di indicatori ai sensi dell’articolo 5, paragrafo 1, lettera c), del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dell’adempimento dei compiti previsti dal regolamento (CE) n. 767/2008, le autorità designate per il VIS di cui all’articolo 9 <span class=\"italics\">quinquies</span> e all’articolo 22 <span class=\"italics\">ter</span>, paragrafo 13, di tale regolamento dispongono del diritto di accesso unicamente a quei dati di ECRIS-TCN conservati nel CIR cui sia stato aggiunto un indicatore ai sensi dell’articolo 5, paragrafo 1, lettera c), del presente regolamento.</p>\n</div>\n</div>"]]}, "7b": {"label": "Articolo 7 ter", "heading": "Utilizzo del sistema ECRIS-TCN per le verifiche ETIAS", "anchor": "art_7b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’esercizio dei compiti conferitile a norma del regolamento (UE) 2018/1240, l’unità centrale ETIAS ha il diritto di accedere e di consultare i dati ECRIS-TCN. Tuttavia l’unità centrale ETIAS ha accesso solo in conformità dell’articolo 11, paragrafo 8, di detto regolamento<span class=\"boldface\">,</span> unicamente ai registri di dati ai quali è stato aggiunto un indicatore ai sensi dell’articolo 5, paragrafo 1, lettera c), del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I dati di cui al primo comma sono utilizzati solo a scopo di verifica da:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità centrale ETIAS, a norma dell’articolo 22 del regolamento (UE) 2018/1240; oppure</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le unità nazionali ETIAS, a norma dell’articolo 25 <span class=\"italics\">bis</span>, paragrafo 2, del regolamento (UE) 2018/1240, ai fini della consultazione dei casellari giudiziali nazionali; il casellario giudiziale nazionale deve essere consultato prima delle valutazioni e delle decisioni di cui all’articolo 26 di tale regolamento e, se del caso, prima delle valutazioni e dei pareri ai sensi dell’articolo 28 di tale regolamento.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il CIR è connesso all’ESP per consentire le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b) del regolamento (UE) 2018/1240.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 24 del regolamento (UE) 2018/1240, le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b) di detto regolamento consente le verifiche successive di cui agli articoli 22 e 26 del medesimo regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini delle verifiche di cui all’articolo 20, paragrafo 2, lettera n), del regolamento (UE) 2018/1240, il sistema centrale ETIAS si avvale dell’ESP per confrontare i dati contenuti nell’ETIAS con i dati ECRIS-TCN provvisti di un indicatore ai sensi dell’articolo 5, paragrafo 1, lettera c), del presente regolamento e dell’articolo 11, paragrafo 8, del regolamento (UE) 2018/1240, utilizzando i dati elencati nella tabella delle corrispondenze di cui all’allegato II del presente regolamento.</p>"]]}, "7c": {"label": "Articolo 7 quater", "heading": "Utilizzo di ECRIS-TCN ai fini degli accertamenti", "anchor": "art_7c", "frags": [[null, "<p class=\"norm\">Le autorità preposte agli accertamenti quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356 hanno il diritto di accedere ai dati di ECRIS-TCN e di interrogarlo, tramite il portale di ricerca europeo di cui all’articolo 6 del regolamento (UE) 2019/818, ai fini dell’esercizio dei compiti loro conferiti dagli articoli 15 e 16 del regolamento (UE) 2024/1356.</p>"], [null, "<p class=\"norm\">Al fine dell’esercizio di tali compiti, le autorità preposte agli accertamenti quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356 hanno diritto di accedere solo alle registrazioni di dati di ECRIS-TCN nel CIR cui è stato apposto un indicatore conformemente all’articolo 5, paragrafo 1, lettera c), del presente regolamento.</p>"], [null, "<p class=\"norm\">In caso di riscontro positivo la consultazione dei casellari giudiziali nazionali in base ai dati di ECRIS-TCN cui è stato apposto un indicatore avviene conformemente al diritto nazionale e usando canali nazionali di comunicazione. Le autorità nazionali rilevanti dello Stato membro di condanna trasmettono un parere alle autorità preposte agli accertamenti, quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356, relativamente al fatto che la presenza di tale persona possa rappresentare una minaccia per la sicurezza interna, entro due giorni se gli accertamenti hanno luogo sul territorio dello Stato membro o entro tre giorni se gli accertamenti hanno luogo alle frontiere esterne. Se le autorità nazionali competenti dello Stato membro di condanna non forniscono il suddetto parere entro tali termini, deve intendersi che non vi sono motivazioni di sicurezza di cui tenere conto. I casellari giudiziali nazionali sono consultati dalle competenti autorità nazionali dello Stato membro di condanna prima di fornire un parere alle autorità preposte agli accertamenti, quali definite all’articolo 2, punto 10), del regolamento (UE) 2024/1356. Se, a seguito di un riscontro positivo, non è stato espresso alcun parere e non vi sono motivazioni di sicurezza di cui tenere conto, tale assenza di parere e di motivazioni di sicurezza sono registrate nel modulo consuntivo di cui all’articolo 17, paragrafo 1, lettera h), del regolamento (UE) 2024/1356.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Periodo di conservazione dei dati", "anchor": "art_8", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuna registrazione di dati è conservata nel sistema centrale e nel CIR fintanto che i dati relativi alla condanna o alle condanne pronunciate a carico dell'interessato sono conservati nel casellario giudiziale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Allo scadere del periodo di conservazione di cui al paragrafo 1, l’autorità centrale dello Stato membro di condanna cancella dal sistema centrale e dal CIR la registrazione di dati, inclusi i dati relativi alle impronte digitali, le immagini del volto o gli indicatori di cui all’articolo 5, paragrafo 1, lettera c). Qualora dal casellario giudiziale nazionale siano cancellati i dati relativi a una condanna per un reato di terrorismo o altro reato di cui all’articolo 5, paragrafo 1, lettera c), ma siano conservate informazioni su altre condanne pronunciate a carico della stessa persona, è unicamente rimosso dalla registrazione di dati l’indicatore di cui all’articolo 5, paragrafo 1, lettera c). Ove possibile, tale cancellazione avviene automaticamente, e in ogni caso non oltre un mese dalla scadenza del periodo di conservazione.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli indicatori di cui all’articolo 5, paragrafo 1, lettera c), sono automaticamente rimossi allo scadere del periodo di conservazione di cui al paragrafo 1 del presente articolo o 25 anni dopo la loro creazione, per quanto riguarda le condanne relative a reati di terrorismo, o 15 anni dopo la loro creazione, per quanto riguarda le condanne relative ad altri reati, a seconda di quale evento si verifichi per primo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Modifica e cancellazione dei dati", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono modificare o cancellare i dati da essi inseriti in <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualsiasi modifica delle informazioni nei casellari giudiziali che hanno generato una registrazione di dati ai sensi dell'articolo 5 include un'identica modifica, senza ingiustificato ritardo, da parte dello Stato membro di condanna, delle informazioni conservate in tale registrazione di dati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora abbia ragione di credere che i dati registrati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> sono inesatti o che sono stati trattati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> in violazione del presente regolamento, lo Stato membro di condanna:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">avvia immediatamente una procedura di verifica dell'esattezza dei dati in questione o, se del caso, della liceità del proprio trattamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove necessario, rettifica o cancella, senza ingiustificato ritardo, i dati dal <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span>.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ove uno Stato membro diverso dallo Stato membro di condanna che ha introdotto i dati abbia ragione di credere che i dati registrati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> sono inesatti o che sono stati trattati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> in violazione del presente regolamento, esso contatta senza ingiustificato ritardo l'autorità centrale dello Stato membro di condanna.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Lo Stato membro di condanna:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">avvia immediatamente una procedura di verifica dell'esattezza dei dati in questione o, se del caso, della liceità del loro trattamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se necessario, rettifica o cancella dal <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> senza ingiustificato ritardo i dati in questione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informa senza ingiustificato ritardo l'altro Stato membro dell'avvenuta rettifica o cancellazione dei dati, o dei motivi per cui i dati non sono stati rettificati né cancellati.</p>\n</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Adozione di atti di esecuzione da parte della Commissione", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione adotta gli atti di esecuzione necessari allo sviluppo tecnico e all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di ECRIS<span class=\"boldface\"> ◄ </span>-TCN quanto prima, in particolare atti riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le specifiche tecniche per il trattamento dei dati alfanumerici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le specifiche tecniche per la qualità, la risoluzione e il trattamento delle impronte digitali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le specifiche tecniche del software di interfaccia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le specifiche tecniche per la qualità, la risoluzione e il trattamento delle immagini del volto per gli scopi e alle condizioni di cui all'articolo 6;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la qualità dei dati, compreso un meccanismo e procedure per lo svolgimento dei controlli di qualità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'inserimento dei dati conformemente all'articolo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'accesso e l'interrogazione di ECRIS-TCN conformemente all'articolo 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la modifica e la cancellazione dei dati conformemente agli articoli 8 e 9;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la conservazione dei registri e l'accesso a essi conformemente all'articolo 31;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1 —————</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'elaborazione di statistiche conformemente all'articolo 32;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti di funzionamento e di disponibilità di ECRIS-TCN, tra cui specifiche e requisiti minimi sulle prestazioni biometriche di ECRIS-TCN, in particolare per quanto riguarda il tasso di falsa identificazione positiva e il tasso di falsa identificazione negativa richiesti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli atti di esecuzione di cui al paragrafo 1 sono adottati secondo la procedura di esame di cui all'articolo 38, paragrafo 2.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Sviluppo e gestione operativa di ECRIS-TCN", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-Lisa è responsabile dello sviluppo dia ECRIS-TCN conformemente al principio della protezione dei dati fin dalla progettazione e per impostazione predefinita. eu-Lisa è altresì responsabile della gestione operativa di ECRIS-TCN. Lo sviluppo comporta l'elaborazione e l'applicazione delle specifiche tecniche, il collaudo e il coordinamento generale del progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">eu-Lisa è inoltre responsabile dello sviluppo ulteriore e della manutenzione dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA definisce la progettazione dell'architettura fisica di ECRIS-TCN, comprese le specifiche tecniche e l'evoluzione per quanto riguarda il sistema centrale, il punto di accesso centrale nazionale e il software d'interfaccia. La progettazione è adottata dal suo consiglio di amministrazione, previo parere favorevole della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">eu-LISA sviluppa e realizza ECRIS-TCN quanto prima dopo l'entrata in vigore del presente regolamento e dopo l'adozione da parte della Commissione degli atti di esecuzione di cui all'articolo 10.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Prima della fase di progettazione e di sviluppo di ECRIS-TCN, il consiglio di amministrazione di eu-LISA istituisce un consiglio di gestione del programma composto di dieci membri.</div>\n</div>"], [null, "<p class=\"norm\">Il consiglio di gestione del programma è costituito da otto membri nominati dal consiglio di amministrazione, dal presidente del gruppo consultivo di cui all'articolo 39 e da un membro nominato dalla Commissione. I membri nominati dal consiglio di amministrazione sono eletti soltanto tra gli Stati membri che sono pienamente vincolati in base al diritto dell'Unione dagli strumenti legislativi che disciplinano ECRIS e che parteciperanno a ECRIS-TCN. Il consiglio di amministrazione garantisce che i membri da esso nominati al consiglio di gestione del programma dispongano dell'esperienza e delle competenze necessarie in termini di sviluppo e gestione di sistemi IT a sostegno delle autorità giudiziarie e delle autorità incaricate dei casellari giudiziali.</p>"], [null, "<p class=\"norm\">eu-LISA partecipa ai lavori del consiglio di gestione del programma. A tal fine, rappresentanti di eu-LISA prendono parte alle riunioni del consiglio di gestione del programma allo scopo di riferire in merito ai lavori relativi alla progettazione e allo sviluppo di ECRIS-TCN e a eventuali altri lavori e attività correlati.</p>"], [null, "<p class=\"norm\">Il consiglio di gestione del programma si riunisce almeno una volta a trimestre e più spesso se necessario. Esso garantisce l'adeguata gestione della fase di progettazione e di sviluppo di ECRIS-TCN e la coerenza tra il progetto centrale e i progetti nazionali dell'ECRIS-TCN, e con il software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di ECRIS<span class=\"boldface\"> ◄ </span>. Il consiglio di gestione del programma presenta regolarmente e se possibile mensilmente, relazioni scritte al consiglio di amministrazione di eu-LISA sui progressi del progetto. Il consiglio di gestione del programma non ha potere decisionale né mandato di rappresentare i membri del consiglio di amministrazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di gestione del programma stabilisce il suo regolamento interno, che comprende in particolare disposizioni concernenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la presidenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i luoghi di riunione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la preparazione delle riunioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'ammissione di esperti alle riunioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i piani di comunicazione atti a garantire che siano tenuti completamente informati i membri non partecipanti del consiglio di amministrazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La presidenza del consiglio di gestione del programma è esercitata da uno Stato membro che è pienamente vincolato, conformemente al diritto dell'Unione, dagli strumenti legislativi che disciplinano ECRIS e dagli strumenti legislativi che disciplinano lo sviluppo, l'istituzione, il funzionamento e l'uso di tutti i sistemi IT su larga scala gestiti da eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Tutte le spese di viaggio e di soggiorno sostenute dai membri del consiglio di gestione del programma sono a carico di eu-LISA. L'articolo 10 del regolamento interno di eu-LISA si applica mutatis mutandis. Il segretariato del consiglio di gestione del programma è assicurato da eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">In fase di progettazione e di sviluppo, il gruppo consultivo di cui all'articolo 39 è composto dei responsabili di progetto nazionali di ECRIS-TCN ed è presieduto da eu-LISA. In fase di progettazione e di sviluppo esso si riunisce regolarmente, se possibile almeno una volta al mese, fino all'entrata in funzione di ECRIS-TCN. Dopo ciascuna riunione, riferisce al consiglio di gestione del programma. Fornisce la consulenza tecnica a sostegno delle attività del consiglio di gestione del programma e monitora lo stato di preparazione degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Al fine di garantire la riservatezza e l'integrità in qualsiasi momento dei dati conservati in ECRIS-TCN, eu-LISA, in cooperazione con gli Stati membri, prevede idonee misure tecniche e organizzative, tenendo conto dello stato dell'arte, del costo relativo all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione<span class=\"boldface\"> ◄ </span> e dei rischi associati al trattamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">eu-LISA è responsabile dei seguenti compiti relativi all'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento delle relazioni tra gli Stati membri e il gestore dell'infrastruttura di comunicazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione è responsabile di tutti gli altri compiti connessi con l'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d), in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compiti relativi all'esecuzione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">acquisizione e rinnovo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aspetti contrattuali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">eu-LISA sviluppa e mantiene un meccanismo e procedure per lo svolgimento dei controlli di qualità sui dati conservati in ECRIS-TCN e riferisce periodicamente agli Stati membri. eu-LISA riferisce periodicamente alla Commissione in merito ai problemi incontrati e agli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">14.  </span>\n<div class=\"norm inline-element\">La gestione operativa di ECRIS-TCN consiste nell'insieme dei compiti necessari per garantirne l'operatività in conformità del presente regolamento e comprende, in particolare, la manutenzione e gli adeguamenti tecnici necessari per garantire che ECRIS-TCN funzioni a un livello soddisfacente conformemente alle specifiche tecniche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">15.  </span>\n<div class=\"norm inline-element\">eu-LISA svolge compiti relativi alla formazione sull'uso tecnico di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">16.  </span>\n<div class=\"norm inline-element\">Fatto salvo l'articolo 17 dello statuto dei funzionari dell'Unione europea di cui al regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (\n<span class=\"superscript\">6</span>\n), eu-LISA applica a tutti i membri del proprio personale che devono lavorare con i dati registrati nel sistema centrale adeguate norme in materia di segreto professionale o altri doveri equivalenti di riservatezza. Questo obbligo vincola tale personale anche dopo che ha lasciato l'incarico o cessato di lavorare, ovvero portato a termine le sue attività.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Responsabilità degli Stati membri", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro è responsabile di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una connessione sicura tra le banche dati nazionali di casellari giudiziali e di impronte digitali e il punto di accesso centrale nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo, il funzionamento e la manutenzione della connessione di cui alla lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una connessione tra il sistema nazionale e l'i<span>\n<span class=\"boldface\">►C1</span>\n</span> mplementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione e le modalità di accesso a ECRIS-TCN del personale debitamente autorizzato delle autorità centrali a norma del presente regolamento, nonché la compilazione e l'aggiornamento periodico di un elenco di tale personale con le qualifiche. di cui all'articolo 19, paragrafo 3, lettera g).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro provvede affinché il personale della sua autorità centrale con diritto di accesso a ECRIS-TCN riceva una formazione adeguata che riguardi, in particolare, le norme di sicurezza e di protezione dei dati e i diritti fondamentali applicabili, prima di autorizzarli a trattare dati conservati nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale dell'ECRIS-TCN e CIR<span class=\"boldface\"> ◄ </span>.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Responsabilità per l'uso dei dati", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Conformemente alle norme applicabili dell'Unione in materia di protezione dei dati, ciascuno Stato membro garantisce che i dati registrati in ECRIS-TCN siano trattati lecitamente e, in particolare, che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soltanto il personale debitamente autorizzato abbia accesso ai dati per assolvere i propri compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati siano raccolti lecitamente e nel pieno rispetto della dignità umana e dei diritti fondamentali del cittadino di paese terzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati siano inseriti lecitamente in ECRIS-TCN;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati inseriti in ECRIS-TCN siano esatti e aggiornati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">eu-LISA garantisce che ECRIS-TCN sia gestito conformemente al presente regolamento, agli atti delegati di cui all'articolo 6, paragrafo 2, e agli atti di esecuzione di cui all'articolo 10, nonché conformemente al regolamento (UE) 2018/1725. In particolare eu-LISA adotta le misure necessarie per garantire la sicurezza del <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale, CIR<span class=\"boldface\"> ◄ </span> e dell'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d), fatte salve le responsabilità di ciascuno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA informa il Parlamento europeo, il Consiglio, la Commissione e il garante europeo della protezione dei dati il più presto possibile delle misure adottate in conformità del paragrafo 2 in vista dell'entrata in funzione dia ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione mette a disposizione degli Stati membri e del pubblico, mantenendo regolarmente aggiornato il sito web, le informazioni di cui al paragrafo 3.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Accesso di Eurojust, Europol ed EPPO", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Eurojust ha accesso diretto a ECRIS-TCN ai fini dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione<span class=\"boldface\"> ◄ </span> dell'articolo 17 e dello svolgimento dei suoi compiti di cui all'articolo 2 del regolamento (UE) 2018/1727, per individuare gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di cittadini di paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Europol ha accesso diretto a ECRIS-TCN ai fini dello svolgimento dei suoi compiti di cui all'articolo 4, paragrafo 1, lettere e) e h), del regolamento (UE) 2016/794, per individuare gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di cittadini di paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">EPPO ha accesso diretto a ECRIS-TCN ai fini dello svolgimento dei suoi compiti di cui all'articolo 4 del regolamento (UE) 2017/1939, per individuare lo Stato membro o gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di cittadini di paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A seguito di riscontro positivo che indichi gli Stati membri in possesso di informazioni sulle condanne pronunciate a carico di un cittadino di paese terzo, Eurojust, Europol ed EPPO possono contattare le autorità nazionali di tali Stati membri per chiedere le informazioni sui casellari giudiziali nel modo previsto nei rispettivi strumenti giuridici costitutivi.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Accesso da parte di personale autorizzato di Eurojust, Europol ed EPPO", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Eurojust, Europol ed EPPO sono responsabili della gestione e delle modalità di accesso a ECRIS-TCN da parte del personale debitamente autorizzato a norma del presente regolamento e della compilazione e dell'aggiornamento periodico di un elenco di tale personale con le relative qualifiche.</p>"]]}, "16": {"label": "Articolo 16", "heading": "Responsabilità di Eurojust, Europol ed EPPO", "anchor": "art_16", "frags": [[null, "<p class=\"norm\">Eurojust, Europol ed EPPO:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabiliscono i mezzi tecnici per connettersi a ECRIS-TCN e sono responsabili del mantenimento della connessione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">forniscono una formazione adeguata che riguardi, in particolare, le norme di sicurezza e di protezione dei dati e i diritti fondamentali applicabili, ai membri del loro personale con diritto di accesso a ECRIS-TCN prima di autorizzarli a trattare dati conservati nel sistema centrale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantiscono che i dati personali che trattano a norma del presente regolamento siano protetti conformemente alle norme applicabili in materia di protezione dei dati.</p>\n</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Punto di contatto per i paesi terzi e le organizzazioni internazionali", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I paesi terzi e le organizzazioni internazionali possono, ai fini di un procedimento penale, indirizzare a Eurojust richieste di informazioni su quali Stati membri, se del caso, siano in possesso di informazioni sul casellario giudiziale di un cittadino di paese terzo. A tale scopo utilizzano il formulario standard che figura nell'allegato del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando riceve una richiesta a norma del paragrafo 1, Eurojust usa ECRIS-TCN per individuare gli eventuali Stati membri in possesso di informazioni sul casellario giudiziale del cittadino di paese terzo interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di riscontro positivo, Eurojust chiede agli Stati membri in possesso di informazioni sul casellario giudiziale del cittadino di paese terzo interessato se acconsentono a che Eurojust informi il paese terzo o l'organizzazione internazionale del nome dello Stato membro interessato. Se tale Stato membro fornisce il proprio consenso, Eurojust comunica al paese terzo o all'organizzazione internazionale il nome di detto Stato membro e le modalità di introduzione di una richiesta di estratti del casellario giudiziale presso gli Stati membri in questione, secondo le procedure applicabili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In assenza di riscontro positivo o qualora non sia in grado di fornire una risposta, conformemente al paragrafo 3, alle richieste che le sono state presentate ai sensi del presente articolo, Eurojust informa il paese terzo o l'organizzazione internazionale in questione di aver completato la procedura, senza precisare se le informazioni sul casellario giudiziale della persona interessata siano in possesso di uno Stato membro.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Comunicazione di informazioni a un paese terzo, a un'organizzazione internazionale o a un soggetto privato", "anchor": "art_18", "frags": [[null, "<p class=\"norm\">Né Eurojust, né Europol, né EPPO, né alcuna delle autorità centrali trasmette a paesi terzi, organizzazioni internazionali o soggetti privati, o mette a loro disposizione, informazioni ottenute tramite ECRIS-TCN relative a un cittadino di paese terzo. Il presente articolo fa salvo l'articolo 17, paragrafo 3.</p>"]]}, "19": {"label": "Articolo 19", "heading": "Sicurezza dei dati", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA adotta le misure necessarie per garantire la sicurezza di ECRIS-TCN, fatte salve le responsabilità di ciascuno Stato membro, tenuto conto delle misure di sicurezza di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda il funzionamento di ECRIS-TCN, eu-LISA adotta le misure necessarie per conseguire gli obiettivi enunciati al paragrafo 3, compresa l'adozione di un piano di sicurezza e di un piano di continuità operativa e di ripristino in caso di disastro, e garantire che i sistemi installati possano, in caso di interruzione, essere ripristinati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri garantiscono la sicurezza dei dati prima e durante la trasmissione al punto di accesso centrale nazionale e il ricevimento dallo stesso. In particolare ciascuno Stato membro:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">protegge fisicamente i dati, tra l'altro mediante l'elaborazione di piani di emergenza per la protezione delle infrastrutture;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nega alle persone non autorizzate l'accesso alle strutture nazionali nelle quali lo Stato membro effettua operazioni connesse a ECRIS-TCN;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedisce che supporti di dati possano essere letti, copiati, modificati o asportati senza autorizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedisce l'inserimento di dati senza autorizzazione e l'ispezione, la modifica o la cancellazione senza autorizzazione di dati personali memorizzati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedisce il trattamento dei dati in ECRIS-TCN senza autorizzazione e la modifica o la cancellazione senza autorizzazione dei dati trattati nel sistema ECRIS-TCN;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che le persone autorizzate ad accedere a ECRIS-TCN abbiano accesso soltanto ai dati previsti dalla loro autorizzazione di accesso, ricorrendo all'identificativo utente individuale e utilizzando esclusivamente modalità di accesso riservato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che tutte le autorità con diritto di accedere a ECRIS-TCN creino profili che descrivono le funzioni e le responsabilità delle persone autorizzate ad accedere ai dati e a inserire, rettificare, cancellare, consultare e interrogare i dati, e mettano senza ingiustificato ritardo tali profili a disposizione delle autorità nazionali di controllo, su richiesta di queste ultime;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce la possibilità di verificare e stabilire a quali organi, organismi e agenzie dell'Unione possano essere trasmessi dati personali mediante apparecchiature di comunicazione dei dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che sia possibile verificare e stabilire quali dati sono stati trattati in ECRIS-TCN, quando, da chi e per quale finalità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedisce, in particolare mediante tecniche appropriate di cifratura, che all'atto della trasmissione di dati personali da ECRIS-TCN o verso di esso, oppure durante il trasporto dei supporti di dati, tali dati personali possano essere letti, copiati, modificati o cancellati senza autorizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controlla l'efficacia delle misure di sicurezza di cui al presente paragrafo e adotta le necessarie misure di carattere organizzativo relative alla verifica e alla verifica interna per garantire l'osservanza del presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">eu-LISA e gli Stati membri cooperano al fine di garantire un approccio coerente alla sicurezza dei dati sulla base di una procedura di gestione del rischio di sicurezza che includa l'intero ECRIS-TCN.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Responsabilità", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le persone o gli Stati membri che hanno subito un danno materiale o non materiale in conseguenza di un trattamento illecito di dati o di qualsiasi altro atto incompatibile con il presente regolamento hanno diritto di ottenere un risarcimento:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dallo Stato membro responsabile del danno; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso in cui eu-LISA non abbia soddisfatto i propri obblighi di cui al presente regolamento o al regolamento (UE) 2018/1725.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro responsabile del danno o eu-LISA sono rispettivamente esonerati in tutto o in parte da tale responsabilità se provano che l'evento dannoso non è loro imputabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro, Eurojust, Europol o EPPO sono rispettivamente responsabili per i danni causati a ECRIS-TCN in caso di inosservanza da parte loro degli obblighi derivanti dal presente regolamento, tranne nel caso e nei limiti in cui eu-LISA o un altro Stato membro che partecipa a ECRIS-TCN abbia omesso di adottare misure ragionevolmente idonee a evitare i danni o a minimizzarne gli effetti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le azioni proposte nei confronti di uno Stato membro per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono disciplinate dal diritto dello Stato membro convenuto. Le azioni proposte nei confronti di eu-LISA, Eurojust, Europol ed EPPO per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono disciplinate dai loro rispettivi strumenti giuridici costitutivi.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Verifica interna", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché ogni autorità centrale adotti le misure necessarie per conformarsi al presente regolamento e cooperi, se necessario, con le autorità di controllo.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Sanzioni", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">L'uso improprio dei dati inseriti in ECRIS-TCN è oggetto di sanzioni o di misure disciplinari effettive, proporzionate e dissuasive, secondo il diritto nazionale o dell'Unione.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Titolare del trattamento e responsabile del trattamento", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda il trattamento dei dati personali effettuato dall'autorità centrale di uno Stato membro a norma del presente regolamento, titolare del trattamento ai sensi delle norme applicabili dell'Unione in materia di protezione dei dati è l'autorità centrale di tale Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda l'inserimento dei dati personali nel <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale e CIR<span class=\"boldface\"> ◄ </span> da parte degli Stati membri, eu-LISA è responsabile del trattamento ai sensi del regolamento (UE) 2018/1725.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Finalità del trattamento dei dati personali", "anchor": "art_24", "frags": [[null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dati inseriti nel sistema centrale e nel CIR sono trattati solo per i fini seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">individuare lo Stato membro o gli Stati membri in possesso di informazioni sui precedenti penali di cittadini di paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo del VIS di valutare se il richiedente un visto, un visto per soggiorno di lunga durata o un permesso di soggiorno costituisca una minaccia per l’ordine pubblico o la sicurezza interna, in conformità del regolamento (CE) n. 767/2008; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo dell’ETIAS di contribuire a un elevato livello di sicurezza, in conformità del regolamento (UE) 2018/1240; o</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenere l’obiettivo di valutare se un cittadino di paese terzo soggetto a un controllo di sicurezza possa rappresentare una minaccia per la sicurezza interna, conformemente al regolamento (UE) 2024/1356.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n</div>\n</div>"], [null, "<p class=\"norm\">I dati inseriti nel CIR sono inoltre trattati in conformità del regolamento (UE) 2019/818 al fine di agevolare e contribuire alla corretta identificazione delle persone registrate nel sistema ECRIS-TCN in conformità del presente regolamento.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ad eccezione del personale debitamente autorizzato di Eurojust, Europol ed EPPO, che ha accesso a ECRIS-TCN ai fini del presente regolamento, l'accesso a ECRIS-TCN è riservato esclusivamente al personale debitamente autorizzato delle autorità centrali. L'accesso è limitato a quanto necessario all'assolvimento dei compiti, conformemente al fine di cui al paragrafo 1, e a quanto necessario e proporzionato agli obiettivi perseguiti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, l'accesso ai fini della consultazione dei dati conservati nel CIR è riservato altresì al personale debitamente autorizzato delle autorità nazionali di ciascuno Stato membro e al personale debitamente autorizzato delle agenzie dell'Unione che sono competenti per gli scopi di cui agli articoli 20 e 21 del regolamento (UE) 2019/818. Tale accesso è limitato conformemente alla misura in cui i dati siano necessari all'assolvimento dei propri compiti per tali scopi, ed è proporzionato agli obiettivi perseguiti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "25": {"label": "Articolo 25", "heading": "Diritto di accesso, rettifica, cancellazione e limitazione del trattamento", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le richieste dei cittadini di paesi terzi relative ai diritti di accesso ai dati personali, di rettifica o cancellazione nonché di limitazione del trattamento, sanciti dalle norme applicabili dell'Unione in materia di protezione dei dati, possono essere presentate all'autorità centrale di ogni Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora la richiesta sia presentata a uno Stato membro diverso da quello di condanna, lo Stato membro al quale è stata presentata la richiesta la trasmette allo Stato membro di condanna senza ingiustificato ritardo e comunque entro di dieci giorni lavorativi dal suo ricevimento. Non appena riceve la richiesta, lo Stato membro di condanna:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">avvia immediatamente una procedura di verifica dell'esattezza dei dati interessati o della liceità del loro trattamento in ECRIS-TCN; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">risponde allo Stato membro che ha presentato la domanda senza ingiustificato ritardo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora emerga che i dati registrati in ECRIS-TCN sono inesatti o sono stati trattati illecitamente, lo Stato membro di condanna provvede a rettificarli o a cancellarli conformemente all'articolo 9. Lo Stato membro di condanna o, ove applicabile, lo Stato membro al quale è stata presentata la richiesta, conferma per iscritto e senza ingiustificato ritardo all'interessato di aver provveduto a rettificare o cancellare i dati che lo riguardano. Lo Stato membro di condanna comunica inoltre senza ingiustificato ritardo quali misure sono state adottate a qualsiasi altro Stato membro che abbia ricevuto informazioni relative alla condanna ottenute da una interrogazione di ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non ritenga che i dati registrati in ECRIS-TCN siano di fatto inesatti o siano stati registrati illecitamente, lo Stato membro di condanna adotta una decisione amministrativa o giudiziaria con la quale illustra per iscritto all'interessato la ragione per cui non intende rettificare o cancellare i dati che lo riguardano. Tali casi possono, se del caso, essere comunicati all'autorità nazionale di controllo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ha adottato la decisione ai sensi del paragrafo 4 fornisce inoltre all'interessato informazioni in merito alla procedura da seguire qualora egli non ritenga accettabile la motivazione fornita ai sensi del paragrafo 4. Tali informazioni comprendono le informazioni sulle modalità per avviare un'azione o un reclamo presso le autorità competenti o le autorità giurisdizionali competenti di tale Stato membro e su qualunque tipo di assistenza, compresa quella delle autorità nazionali di controllo, disponibile in conformità del diritto nazionale di tale Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualsiasi richiesta presentata a norma del paragrafo 1 contiene le informazioni necessarie per identificare l'interessato. Tali informazioni sono utilizzate unicamente per consentire l'esercizio dei diritti di cui al paragrafo 1 e sono cancellate subito dopo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se si applica il paragrafo 2, l'autorità centrale a cui è stata presentata la richiesta conserva una registrazione scritta della presentazione di tale richiesta e di come e a quale autorità è stata trasmessa. Su richiesta dell'autorità di controllo nazionale, l'autorità centrale mette senza ritardo tale registrazione a disposizione di tale autorità nazionale di controllo. L'autorità centrale e l'autorità nazionale di controllo cancellano tali registrazioni tre anni dopo la loro creazione.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Cooperazione volta a garantire il rispetto dei diritti relativi alla protezione dei dati", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità centrali cooperano per garantire il rispetto dei diritti sanciti dall'articolo 25.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In ciascuno Stato membro l'autorità nazionale di controllo fornisce, su richiesta, informazioni agli interessati sull'esercizio del diritto di rettifica o cancellazione dei dati che li riguardano, ai sensi delle norme applicabili dell'Unione in materia di protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del presente articolo, l'autorità nazionale di controllo dello Stato membro che ha trasmesso i dati e l'autorità di controllo nazionali dello Stato membro alle quali è stata presentata la richiesta cooperano per raggiungere tali obiettivi.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Mezzi di ricorso", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">Chiunque ha il diritto di presentare un reclamo e il diritto a un ricorso giuridico nello Stato membro di condanna che abbia negato il diritto di cui all'articolo 25, di ottenere l'accesso ovvero la rettifica o la cancellazione dei dati che lo riguardano, in conformità del diritto nazionale o dell'Unione.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Vigilanza da parte delle autorità nazionali di controllo", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro assicura che le autorità nazionali di controllo designate in conformità delle norme applicabili dell'Unione in materia di protezione dei dati verifichino la liceità del trattamento dei dati personali di cui agli articoli 5 e 6 effettuato dallo Stato membro in questione, nonché il loro trasferimento al e da ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità nazionale di controllo provvede affinché, almeno ogni tre anni dalla data dell'entrata in funzione di ECRIS-TCN, sia svolto un audit dei trattamenti di dati nelle banche dati nazionali di casellari giudiziali e di impronte digitali relativamente allo scambio di dati tra tali sistemi e ECRIS-TCN, conformemente ai pertinenti principi internazionali di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le loro autorità nazionali di controllo dispongano delle risorse sufficienti per assolvere i compiti a esse affidati dal presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro comunica qualsiasi informazione richiesta dalle autorità nazionali di controllo e, in particolare, fornisce loro informazioni sulle attività svolte conformemente agli articoli 12, 13 e 19. Ciascuno Stato membro consente alle proprie autorità nazionali di controllo di consultare le registrazioni conformemente all'articoli 25, paragrafo 7, e l'accesso ai propri registri conformemente all'articolo 31, paragrafo 6, e consente loro l'accesso in qualsiasi momento a tutti i suoi locali utilizzati per ECRIS-TCN.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Vigilanza da parte del garante europeo della protezione dei dati", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il garante europeo della protezione dei dati verifica che le attività di trattamento dei dati personali da parte di eu-LISA concernenti ECRIS-TCN siano effettuate in conformità del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il garante europeo della protezione dei dati provvede affinché, almeno ogni tre anni, sia svolto un audit delle attività di trattamento dei dati personali effettuate da eu-LISA, conformemente ai pertinenti principi internazionali di audit. Una relazione su tale audit è trasmessa al Parlamento europeo, al Consiglio, alla Commissione, a eu-LISA e alle autorità di controllo. A eu-LISA è data la possibilità di presentare osservazioni prima dell'adozione della relazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA fornisce al garante europeo della protezione dei dati le informazioni da questo richieste, gli permette di consultare tutti i documenti e i registri di cui all'articolo 31 e di avere accesso, in qualsiasi momento, a tutti i suoi locali.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Cooperazione tra le autorità nazionali di controllo e il garante europeo della protezione dei dati", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">È assicurato il controllo coordinato di ECRIS-TCN a norma dell'articolo 62 del regolamento (UE) 2018/1725.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Registri", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA e le autorità competenti provvedono, nei limiti delle responsabilità rispettive, affinché tutti i trattamenti di dati in ECRIS-TCN siano registrati conformemente al paragrafo 2 al fine di verificare l'ammissibilità delle richieste e monitorare l'integrità e la sicurezza dei dati e la liceità del trattamento dei dati, nonché a fini di verifica interna.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il registro indica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo scopo della richiesta di accesso ai dati di ECRIS-TCN;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati trasmessi di cui all'articolo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il riferimento dell'archivio nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data e l'ora esatta del trattamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati usati per l'interrogazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'identificazione del funzionario che ha effettuato la consultazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il registro delle consultazioni e delle comunicazioni consente di stabilire la motivazione di tali operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I registri sono usati solo ai fini della verifica della liceità del trattamento dei dati e per garantire l'integrità e la sicurezza dei dati. Soltanto i registri che non contengono dati personali possono essere usati ai fini della verifica e della valutazione di cui all'articolo 36. Tali registri sono protetti dall'accesso non autorizzato con misure adeguate e sono cancellati dopo tre anni, sempreché non siano stati richiesti per procedure di verifica già avviate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Su richiesta, eu-LISA mette a disposizione delle autorità centrali, senza ingiustificato ritardo, i registri dei propri trattamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le autorità nazionali di controllo competenti a verificare l'ammissibilità della richiesta e la liceità del trattamento dei dati, l'integrità e la sicurezza dei dati, hanno accesso ai registri, su loro richiesta per l'adempimento delle loro funzioni. Su richiesta, le autorità centrali mettono a disposizione delle autorità nazionali di controllo competenti, senza ingiustificato ritardo, i registri dei propri trattamenti.</div>\n</div>"]]}, "31a": {"label": "Articolo 31 bis", "heading": "Tenuta dei registri ai fini dell’interoperabilità con il VIS", "anchor": "art_31a", "frags": [[null, "<p class=\"norm\">Per le consultazioni di cui all’articolo 7 <span class=\"italics\">bis</span> del presente regolamento è conservato un registro di ciascun trattamento dei dati di ECRIS-TCN eseguito nel CIR e nel VIS, in conformità dell’articolo 34 del regolamento (CE) n. 767/2008.</p>"]]}, "31b": {"label": "Articolo 31 ter", "heading": "Tenuta dei registri ai fini dell’interoperabilità con l’ETIAS", "anchor": "art_31b", "frags": [[null, "<p class=\"norm\">Per le consultazioni di cui all’articolo 7 <span class=\"italics\">ter</span> del presente regolamento è conservata una registrazione di tutti i trattamenti di dati ECRIS-TCN eseguiti nel CIR e nell’ETIAS, in conformità dell’articolo 69 del regolamento (UE) 2018/1240.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Uso dei dati per l'elaborazione di relazioni e statistiche", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il personale debitamente autorizzato di eu-LISA, delle autorità competenti e della Commissione è abilitato a consultare i dati trattati in ECRIS-TCN unicamente per elaborare relazioni e statistiche e senza che sia possibile l'identificazione individuale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, eu-LISA conserva i dati di cui a tale paragrafo nell'archivio centrale per le relazioni e le statistiche di cui all'articolo 39 del regolamento (UE) 2019/818.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le procedure poste in essere da eu-LISA per monitorare il funzionamento di ECRIS-TCN di cui all'articolo 36 e l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> comprendono la possibilità di produrre statistiche periodiche a fini di monitoraggio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Ogni mese eu-LISA trasmette alla Commissione statistiche relative alla registrazione, alla conservazione e allo scambio delle informazioni estratte dai casellari giudiziali tramite ECRIS-TCN e l’implementazione di riferimento ECRIS, comprese le statistiche relative ai record di dati contenenti un indicatore di cui all’articolo 5, paragrafo 1, lettera c). eu-LISA garantisce che non sia possibile identificare persone fisiche sulla base di tali statistiche. Su richiesta della Commissione, eu-LISA le fornisce statistiche su aspetti specifici connessi all’attuazione del presente regolamento.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri forniscono a eu-LISA le statistiche necessarie per adempiere agli obblighi di cui al presente articolo. Essi forniscono alla Commissione statistiche relative al numero di cittadini di paesi terzi condannati e al numero di condanne di cittadini di paesi terzi sul loro territorio.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Spese", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le spese sostenute per l'istituzione e il funzionamento del <span>\n<span class=\"boldface\">►M1</span>\n</span> sistema centrale, CIR e<span class=\"boldface\"> ◄ </span>, dell'infrastruttura di comunicazione di cui all'articolo 4, paragrafo 1, lettera d), del software di interfaccia e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> sono a carico del bilancio generale dell'Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le spese di connessione di Eurojust, Europol ed EPPO a ECRIS-TCN sono a carico del loro rispettivo bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Altre spese sono a carico degli Stati membri, in particolare quelle sostenute per la connessione dei registri nazionali di casellari giudiziali, delle banche dati di impronte digitali e delle autorità centrali a ECRIS-TCN, e le spese di hosting dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Comunicazioni", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro comunica a eu-LISA l'autorità centrale o le autorità centrali che dispongono dell'accesso per inserire, rettificare, cancellare, consultare e interrogare i dati e la informa di ogni eventuale cambiamento al riguardo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">eu-LISA provvede alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> e sul suo sito web dell'elenco delle autorità centrali comunicate dagli Stati membri. Non appena riceve la comunicazione di un cambiamento dell'autorità centrale di uno Stato membro, eu-LISA aggiorna l'elenco senza ingiustificato ritardo.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Inserimento dei dati ed entrata in funzione", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione determina la data a partire dalla quale gli Stati membri iniziano a inserire in ECRIS-TCN i dati di cui all'articolo 5 una volta che ha accertato che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano stati adottati gli atti di esecuzione pertinenti di cui all'articolo 10;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri abbiano convalidato le necessarie disposizioni tecniche e giuridiche per raccogliere e trasmettere a ECRIS-TCN i dati di cui all'articolo 5 e le abbiano comunicate alla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eu-LISA abbia effettuato un collaudo generale di ECRIS-TCN, in cooperazione con gli Stati membri, utilizzando dati di prova anonimi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando la Commissione ha determinato la data di inizio dell'inserimento dei dati conformemente al paragrafo 1, la comunica agli Stati membri. Entro un periodo di due mesi a decorrere da tale data gli Stati membri inseriscono in ECRIS-TCN i dati di cui all'articolo 5, tenendo conto dell'articolo 41, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Alla fine del periodo di cui al paragrafo 2, eu-LISA esegue un collaudo finale di ECRIS-TCN, in cooperazione con gli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando il collaudo di cui al paragrafo 3 è stato completato con successo ed eu-LISA ritiene che ECRIS-TCN sia pronto a entrare in funzione, essa lo comunica alla Commissione. La Commissione informa il Parlamento europeo e il Consiglio dell'esito del collaudo e decide la data a partire dalla quale ECRIS-TCN entra in funzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione sulla data di entrata in funzione di ECRIS-TCN, di cui al paragrafo 4, è pubblicata nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri iniziano a utilizzare ECRIS-TCN a decorrere dalla data stabilita dalla Commissione ai sensi del paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Nell'adottare le decisioni di cui al presente articolo, la Commissione può fissare date diverse per l'inserimento in ECRIS-TCN dei dati alfanumerici e dei dati relativi alle impronte digitali di cui all'articolo 5, nonché per l'entrata in funzione relativamente a tali diverse categorie di dati.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Monitoraggio e valutazione", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA provvede affinché siano istituite procedure per monitorare lo sviluppo di ECRIS-TCN rispetto agli obiettivi relativi alla programmazione e ai costi, nonché a monitorare il funzionamento di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> rispetto agli obiettivi concernenti i risultati tecnici, il rapporto costi/benefici, la sicurezza e la qualità del servizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del monitoraggio del funzionamento di ECRIS-TCN e della sua manutenzione tecnica, eu-LISA ha accesso alle informazioni necessarie riguardanti i trattamenti dei dati effettuati in ECRIS-TCN e nell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 10 dicembre 2019 e successivamente ogni sei mesi durante la fase di progettazione e sviluppo, eu-LISA presenta al Parlamento europeo e al Consiglio una relazione sullo sviluppo di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS.<span class=\"boldface\"> ◄ </span>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La relazione di cui al paragrafo 3 include una panoramica dei costi attuali e dell'evoluzione del progetto, una valutazione dell'impatto finanziario, nonché informazioni su eventuali problemi tecnici e rischi suscettibili di ripercuotersi sui costi complessivi di ECRIS-TCN a carico del bilancio generale dell'Unione in conformità dell'articolo 33.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di importante ritardo nel processo di sviluppo, eu-LISA informa il Parlamento europeo e il Consiglio quanto prima dei motivi di tale ritardo, nonché del relativo impatto finanziario e sul calendario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Una volta che lo sviluppo di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> è completato, eu-LISA presenta una relazione al Parlamento europeo e al Consiglio che illustra in che modo gli obiettivi sono stati conseguiti, in particolare per quanto riguarda la programmazione e i costi, giustificando eventuali scostamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Nel caso di un aggiornamento tecnico di ECRIS-TCN, che potrebbe comportare costi elevati, eu-LISA informa il Parlamento europeo e il Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Due anni dopo l'entrata in funzione di ECRIS-TCN e successivamente ogni anno, eu-LISA presenta alla Commissione una relazione sul funzionamento tecnico di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, compresa la loro sicurezza, basata in particolare sulle statistiche relative al funzionamento e all'uso di ECRIS-TCN e allo scambio, tramite l'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, delle informazioni estratte dai casellari giudiziali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Quattro anni dopo l'entrata in funzione di ECRIS-TCN e successivamente ogni quattro anni, la Commissione effettua una valutazione globale di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>. La relazione di valutazione globale elaborata su questa base comprende una valutazione dell'applicazione del presente regolamento e un'analisi concernente i risultati conseguiti in relazione agli obiettivi fissati e l'incidenza sui diritti fondamentali. Sono incluse inoltre una valutazione della perdurante validità dei principi di base del funzionamento di ECRIS-TCN, una valutazione dell'adeguatezza dell'uso dei dati biometrici ai fini del funzionamento di ECRIS-TCN, della sicurezza di ECRIS-TCN e delle eventuali implicazioni in termini di sicurezza per le future attività. La valutazione comprende le necessarie raccomandazioni. La Commissione trasmette la relazione al Parlamento europeo, al Consiglio, al garante europeo della protezione dei dati e all'Agenzia dell'Unione europea per i diritti fondamentali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, la prima valutazione globale di cui al paragrafo 9 include una valutazione dei seguenti aspetti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la misura in cui, sulla base dei pertinenti dati statistici e delle ulteriori informazioni fornite dagli Stati membri, l'inclusione in ECRIS-TCN di informazioni sull'identità di cittadini dell'Unione che possiedono anche la cittadinanza di un paese terzo ha contribuito al conseguimento degli obiettivi del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità, per alcuni Stati membri, di continuare a usare il software nazionale di <span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione ECRIS<span class=\"boldface\"> ◄ </span>, ai sensi dell'articolo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'inserimento dei dati relativi alle impronte digitali in ECRIS-TCN, in particolare l'applicazione dei criteri minimi di cui all'articolo 5, paragrafo 1, lettera b), punto ii);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'incidenza di ECRIS e di ECRIS-TCN sulla protezione dei dati di carattere personale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La valutazione può, se necessario, essere corredata di proposte legislative. Le valutazioni globali successive possono includere una valutazione di uno o di tutti questi aspetti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Gli Stati membri, Eurojust, Europol ed EPPO comunicano a eu-LISA e alla Commissione le informazioni necessarie per redigere le relazioni di cui ai paragrafi 3, 8 e 9 conformemente agli indicatori quantitativi predefiniti dalla Commissione o da eu-LISA, o da entrambe. Tali informazioni non mettono a repentaglio i metodi di lavoro, né comprendono indicazioni sulle fonti, sui membri del personale o sulle indagini.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Ove opportuno, le autorità di controllo comunicano a eu-LISA e alla Commissione le informazioni necessarie per redigere le relazioni di cui al paragrafo 9 conformemente agli indicatori quantitativi predefiniti dalla Commissione o da eu-LISA, o da entrambe. Tali informazioni non mettono a repentaglio i metodi di lavoro, né comprendono indicazioni sulle fonti, sui membri del personale o sulle indagini.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">eu-LISA comunica alla Commissione le informazioni necessarie per elaborare le valutazioni globali di cui al paragrafo 9.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Esercizio della delega", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 6, paragrafo 2, è conferito alla Commissione per un periodo indeterminato a decorrere dal 9 giugno 2019.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all'articolo 6, paragrafo 2, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell'adozione dell'atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell'accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L'atto delegato adottato ai sensi dell'articolo 6, paragrafo 2, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Procedura di comitato", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l'articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Gruppo consultivo", "anchor": "art_39", "frags": [[null, "<p class=\"norm\">eu-LISA istituisce un gruppo consultivo allo scopo di ottenere consulenza tecnica relativa a ECRIS-TCN e all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, in particolare nell'ambito della preparazione del programma di lavoro annuale e della relazione annuale di attività. In fase di progettazione e di sviluppo si applica l'articolo 11, paragrafo 9.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Modifiche del regolamento (UE) 2018/1726", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) 2018/1726 è cosi modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 1, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">L'Agenzia è responsabile della preparazione, dello sviluppo o della gestione operativa del sistema di ingressi/uscite (EES), di DubliNet, del sistema europeo di informazione e autorizzazione ai viaggi (ETIAS), di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito l'articolo seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 8 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Compiti relativi a ECRIS-TCN e all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>\n</p>\n<p class=\"norm\">Con riguardo a ECRIS-TCN e all'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, l'Agenzia svolge:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all'Agenzia conformemente al regolamento (UE) 2019/816 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*1</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull'uso tecnico di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 14, il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">L'Agenzia segue gli sviluppi della ricerca per la gestione operativa del SIS II, del VIS, di Eurodac, dell'EES, dell'ETIAS, di DubliNet, di ECRIS-TCN e di altri sistemi IT su larga scala di cui all'articolo 1, paragrafo 5.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 19, il paragrafo 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera ee) è sostituita dalla seguente:</p>\n<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">«ee)<span style=\"word-spacing: 15pt\"> </span>adotta le relazioni sullo sviluppo dell'EES conformemente all'articolo 72, paragrafo 2, del regolamento (UE) 2017/2226, le relazioni sullo sviluppo dell'ETIAS conformemente all'articolo 92, paragrafo 2, del regolamento (UE) 2018/1240 e le relazioni sullo sviluppo di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> conformemente all'articolo 36, paragrafo 3, del regolamento (UE) 2019/816;»;</p>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera ff) è sostituita dalla seguente:</p>\n<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">«ff)<span style=\"word-spacing: 19pt\"> </span>adotta le relazioni sul funzionamento tecnico del SIS II in conformità, rispettivamente, dell'articolo 50, paragrafo 4, del regolamento (CE) n. 1987/2006 e dell'articolo 66, paragrafo 4, della decisione 2007/533/GAI, del VIS in conformità dell'articolo 50, paragrafo 3, del regolamento (CE) n. 767/2008 e dell'articolo 17, paragrafo 3, della decisione 2008/633/GAI, dell'EES in conformità dell'articolo 72, paragrafo 4, del regolamento (UE) 2017/2226, dell'ETIAS in conformità dell'articolo 92, paragrafo 4, del regolamento (UE) 2018/1240, e di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> in conformità dell'articolo 36, paragrafo 8, del regolamento (UE) 2019/816;»;</p>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera hh) è sostituita dalla seguente:</p>\n<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">«hh)<span style=\"word-spacing: 15pt\"> </span>adotta osservazioni formali sulle relazioni del Garante europeo della protezione dei dati relative ai controlli svolti conformemente all'articolo 45, paragrafo 2, del regolamento (CE) n. 1987/2006, all'articolo 42, paragrafo 2, del regolamento (CE) n. 767/2008 e all'articolo 31, paragrafo 2, del regolamento (UE) n. 603/2013, all'articolo 56, paragrafo 2, del regolamento (UE) 2017/2226 e all'articolo 67 del regolamento (UE) 2018/1240 e all'articolo 29, paragrafo 2, del regolamento (UE) 2019/816, e assicura adeguato seguito a tali controlli e audit;»;</p>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserita la lettera seguente:</p>\n<div style=\"margin-left: 54pt; text-indent: -54pt\">\n<p class=\"norm\">«ll bis)<span style=\"word-spacing: NaNpt\"> </span>trasmette alla Commissione statistiche su ECRIS-TCN e sull'<span>\n<span class=\"boldface\">►C1</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> conformemente all'articolo 32, paragrafo 4, secondo comma, del regolamento (UE) 2019/816;»;</p>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera mm) è sostituita dalla seguente:</p>\n<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">«mm)<span style=\"word-spacing: 11pt\"> </span>provvede alla pubblicazione annuale dell'elenco delle autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS II in conformità dell'articolo 31, paragrafo 8, del regolamento (CE) n. 1987/2006 e dell'articolo 46, paragrafo 8, della decisione 2007/533/GAI, e dell'elenco degli uffici dei sistemi nazionali del SIS II (uffici N.SIS II) e degli uffici SIRENE in conformità, rispettivamente, dell'articolo 7, paragrafo 3, del regolamento (CE) n. 1987/2006 e dell'articolo 7, paragrafo 3, della decisione 2007/533/GAI, nonché dell'elenco delle autorità competenti di cui all'articolo 65, paragrafo 2, del regolamento (UE) 2017/2226 e dell'elenco delle autorità competenti di cui all'articolo 87, paragrafo 2, del regolamento (UE) 2018/1240 e dell'elenco delle autorità centrali di cui all'articolo 34, paragrafo 2, del regolamento (UE) 2019/816;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 22, paragrafo 4 è inserito il seguente comma dopo il terzo comma:</p>\n<p class=\"norm\">«Europol, Eurojust ed EPPO possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori quando sono all'ordine del giorno questioni concernenti ECRIS-TCN in relazione all'applicazione del regolamento (UE) 2019/816.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 24, paragrafo 3, la lettera p) è sostituita dalla seguente:</p>\n<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">«p)<span style=\"word-spacing: 15pt\"> </span>stabilire, fatto salvo l'articolo 17 dello statuto, le clausole di riservatezza per conformarsi all'articolo 17 del regolamento (CE) n. 1987/2006, all'articolo 17 della decisione 2007/533/GAI, all'articolo 26, paragrafo 9, del regolamento (CE) n. 767/2008, all'articolo 4, paragrafo 4, del regolamento (UE) n. 603/2013, all'articolo 37, paragrafo 4, del regolamento (UE) 2017/2226, all'articolo 74, paragrafo 2, del regolamento (UE) 2018/1240 e all'articolo 11, paragrafo 16, del regolamento (UE) 2019/816;»;</p>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 27, paragrafo 1, è inserito il seguente punto:</p>\n<div style=\"margin-left: 48pt; text-indent: -48pt\">\n<p class=\"norm\">«d <span class=\"italics\">bis</span>)<span style=\"word-spacing: NaNpt\"> </span>gruppo consultivo di ECRIS-TCN;».</p>\n</div>\n</div>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "►C1 Implementazione ◄ e disposizioni transitorie", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano quanto prima le misure necessarie per conformarsi al presente regolamento in modo da garantire il corretto funzionamento di ECRIS-TCN.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le condanne pronunciate prima della data dell'avvio dell'inserimento dei dati ai sensi dell'articolo 35, paragrafo 1, le autorità centrali creano la registrazione di dati individuale nel sistema centrale e nel CIR come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati alfanumerici che devono essere inseriti nel sistema centrale e nel CIR entro la fine del periodo di cui all'articolo 35, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati relativi alle impronte digitali che devono essere inseriti nel CIR entro due anni dall'entrata in funzione ai sensi dell'articolo 35, paragrafo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "42": {"label": "Articolo 42", "heading": "Entrata in vigore", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}}, "recitals": {}};